// PARSE + SCHEMA-VALIDATE the AI's suggestion (no AI here).
// Mirrors src/lib/content/extraction-schema.ts: validation FAILURE => the post
// goes to the MANUAL path; it is NEVER auto-published. Fail-closed.
const TYPES = ['meal_plan','reflection','health_notice','event_notice','info'];
const ISO = /^\d{4}-\d{2}-\d{2}$/;
const HHMM = /^([01]\d|2[0-3]):[0-5]\d$/;

let out = { ok: false, errors: ['no/invalid AI response (fail-closed)'], suggestion: null };
try {
  const raw = $json.content?.[0]?.text ?? $json.text ?? '';
  const obj = JSON.parse(raw.replace(/```json|```/g, '').trim());
  const errors = [];

  // 1. content_type_suggested must be in the closed taxonomy.
  if (!TYPES.includes(obj.content_type_suggested)) errors.push('content_type_suggested not in taxonomy');
  // 2. title present.
  if (typeof obj.title !== 'string' || !obj.title.trim()) errors.push('title missing');
  // 3. events: every starts_on must be a real ISO date; times valid or empty.
  const events = Array.isArray(obj.events) ? obj.events : [];
  events.forEach((e, i) => {
    if (!ISO.test(e.starts_on || '')) errors.push(`event[${i}].starts_on not ISO`);
    if (e.time_start && !HHMM.test(e.time_start)) errors.push(`event[${i}].time_start invalid`);
    if (typeof e.all_day !== 'boolean') errors.push(`event[${i}].all_day not boolean`);
  });
  // 4. ambiguous_dates must be an array (the model must DECLARE what it couldn't resolve, not invent).
  if (!Array.isArray(obj.ambiguous_dates)) errors.push('ambiguous_dates not an array');

  if (errors.length === 0) out = { ok: true, errors: [], suggestion: obj };
  else out = { ok: false, errors, suggestion: obj };
} catch (e) {
  out = { ok: false, errors: ['unparseable AI JSON (fail-closed)'], suggestion: null };
}

return [{ json: { ...out, route: out.ok ? 'to_review_gate' : 'to_manual_path' } }];
